# Convert deep recursion to iteration with explicit stack
def flatten_iterative(nested):
    stack = [nested]
    result = []
    while stack:
        item = stack.pop()
        if isinstance(item, list):
            stack.extend(reversed(item))    # push children
        else:
            result.append(item)
    return result

from functools import lru_cache

# Without memoization: O(2^n) — catastrophically slow for large n
def fib(n):
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)

# With lru_cache: O(n) — each subproblem computed once
@lru_cache(maxsize=None)
def fib(n):
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)

print(fib(100))    # 354224848179261915075 — instant

from typing import Optional, Union, Callable

def greet(name: str, times: int = 1) -> str:
    return (f"Hello, {name}!\n" * times).strip()

def process(
    data: list[dict],
    transform: Callable[[dict], dict],
    filter_fn: Optional[Callable[[dict], bool]] = None,
) -> list[dict]:
    results = [transform(item) for item in data]
    if filter_fn is not None:
        results = [r for r in results if filter_fn(r)]
    return results

