import time
import logging
import functools
from typing import Callable, Any

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# --- Decorators ---

def log_calls(func: Callable) -> Callable:
    """Log entry and exit of every function call."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        logger.info(f"→ {func.__name__}({args}, {kwargs})")
        result = func(*args, **kwargs)
        logger.info(f"← {func.__name__} returned {result!r}")
        return result
    return wrapper

def validate_types(**expected_types):
    """Decorator factory: enforce argument types at runtime."""
    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            sig = func.__code__.co_varnames
            bound = dict(zip(sig, args))
            bound.update(kwargs)
            for param, expected in expected_types.items():
                if param in bound and not isinstance(bound[param], expected):
                    raise TypeError(
                        f"{func.__name__}: '{param}' must be "
                        f"{expected.__name__}, got {type(bound[param]).__name__}"
                    )
            return func(*args, **kwargs)
        return wrapper
    return decorator

def rate_limit(calls_per_second: float):
    """Decorator factory: enforce a minimum interval between calls."""
    min_interval = 1.0 / calls_per_second
    last_called = [0.0]    # mutable container to allow closure mutation

    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            elapsed = time.monotonic() - last_called[0]
            if elapsed < min_interval:
                time.sleep(min_interval - elapsed)
            last_called[0] = time.monotonic()
            return func(*args, **kwargs)
        return wrapper
    return decorator

# --- Processing pipeline ---

@log_calls
@validate_types(user_id=int, payload=dict)
def validate_request(user_id: int, payload: dict) -> dict:
    if not payload.get("action"):
        raise ValueError("Request must include 'action'")
    return {"user_id": user_id, "payload": payload, "valid": True}

@rate_limit(calls_per_second=10)
def enrich_request(request: dict) -> dict:
    """Attach metadata — rate-limited to 10 requests/sec."""
    return {**request, "timestamp": time.time(), "version": "v2"}

def build_pipeline(*stages: Callable) -> Callable:
    """Compose multiple processing stages into one function."""
    def pipeline(data: Any) -> Any:
        for stage in stages:
            data = stage(data)
        return data
    return pipeline

# Assemble the pipeline
process_request = build_pipeline(
    lambda r: validate_request(r["user_id"], r["payload"]),
    enrich_request,
)

# Drive the pipeline
requests = [
    {"user_id": 1, "payload": {"action": "read", "resource": "posts"}},
    {"user_id": 2, "payload": {"action": "write", "resource": "comments"}},
]

for raw in requests:
    result = process_request(raw)
    print(result)
